using ContosoUniversity.Services;
using ContosoUniversity.Models;
using Xunit;
using System;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue after each test
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("Student", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("42", notification.Message);
        }

        [Fact]
        public void SendNotification_Create_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Course 'Chemistry' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_Update_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_Delete_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToNow()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _service.SendNotification("First", "1", EntityOperation.CREATE);
            _service.SendNotification("Second", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            Assert.Equal("First", first.EntityType);
            Assert.Equal("Second", second.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllRetrievable()
        {
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }
            Assert.Equal(5, count);
        }

        [Fact]
        public void SendNotification_SimpleOverload_CallsTwoParamOverload()
        {
            _service.SendNotification("Department", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Department", notification.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("DELETE", notification.Operation);
        }

        [Fact]
        public void SendNotification_WithNullDisplayName_UsesIdFallback()
        {
            _service.SendNotification("Student", "99", null, EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("99", notification.Message);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdFallback()
        {
            _service.SendNotification("Student", "99", "", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("99", notification.Message);
        }

        [Fact]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdFallback()
        {
            _service.SendNotification("Student", "99", "   ", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("99", notification.Message);
        }
    }
}

using Xunit;
using System.Linq;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 3, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_WhenPageIndexGreaterThan1()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.True(list.HasNextPage); // TotalPages=2, PageIndex=1
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.False(list.HasNextPage); // TotalPages=2, PageIndex=2
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages); // ceil(25/10) = 3
            Assert.Equal(10, result.Count);
            Assert.Equal(11, result.First());
            Assert.Equal(20, result.Last());
        }

        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(1, result.First());
        }

        [Fact]
        public void Create_LastPage_ReturnsFewer()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(3, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(2, result.Count); // only 11, 12
        }

        [Fact]
        public void Create_SinglePage_HasNoPreviousOrNext()
        {
            var source = Enumerable.Range(1, 3).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatesCorrectlyWithExactDivision()
        {
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);
            Assert.Equal(4, list.TotalPages); // 20/5 = 4 exactly
        }

        [Fact]
        public void TotalPages_CalculatesCorrectlyWithRemainder()
        {
            var list = new PaginatedList<int>(new List<int>(), 21, 1, 5);
            Assert.Equal(5, list.TotalPages); // ceil(21/5) = 5
        }

        [Fact]
        public void TotalPages_IsOne_WhenCountEqualsPageSize()
        {
            var list = new PaginatedList<int>(new List<int>(), 5, 1, 5);
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }
    }
}

