{"file_text": "using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_HasAllDbSets()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Courses);
            Assert.NotNull(context.Enrollments);
            Assert.NotNull(context.Departments);
            Assert.NotNull(context.OfficeAssignments);
            Assert.NotNull(context.CourseAssignments);
            Assert.NotNull(context.People);
            Assert.NotNull(context.Students);
            Assert.NotNull(context.Instructors);
            Assert.NotNull(context.Notifications);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            using var context = TestDbContextFactory.Create();
            var entityType = context.Model.FindEntityType(typeof(CourseAssignment));
            var primaryKey = entityType!.FindPrimaryKey();
            Assert.NotNull(primaryKey);
            Assert.Equal(2, primaryKey.Properties.Count);
            Assert.Contains(primaryKey.Properties, p => p.Name == "CourseID");
            Assert.Contains(primaryKey.Properties, p => p.Name == "InstructorID");
        }

        [Fact]
        public void Person_UsesTPH_Inheritance()
        {
            using var context = TestDbContextFactory.Create();
            var personEntity = context.Model.FindEntityType(typeof(Person));
            Assert.NotNull(personEntity);
            var discriminator = personEntity.FindDiscriminatorProperty();
            Assert.NotNull(discriminator);
            Assert.Equal("Discriminator", discriminator.Name);
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestDbContextFactory.Create();
            context.Students.Add(new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = System.DateTime.Now
            });
            context.SaveChanges();

            var student = context.Students.First();
            Assert.Equal("Test", student.FirstMidName);
            Assert.Equal("User", student.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            using var context = TestDbContextFactory.Create();
            context.Instructors.Add(new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = System.DateTime.Now
            });
            context.SaveChanges();

            var instructor = context.Instructors.First();
            Assert.Equal("Test", instructor.FirstMidName);
        }

        [Fact]
        public void CanAddCourseWithDepartment()
        {
            using var context = TestDbContextFactory.Create();
            var dept = new Department
            {
                Name = "Science",
                Budget = 100000,
                StartDate = System.DateTime.Now
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            context.Courses.Add(new Course
            {
                CourseID = 9999,
                Title = "Physics",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            });
            context.SaveChanges();

            var course = context.Courses.Include(c => c.Department).First(c => c.CourseID == 9999);
            Assert.Equal("Science", course.Department.Name);
        }

        [Fact]
        public void OfficeAssignment_HasOneToOneRelationship()
        {
            using var context = TestDbContextFactory.Create();
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Inst",
                HireDate = System.DateTime.Now
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            });
            context.SaveChanges();

            var loaded = context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.ID == instructor.ID);
            Assert.NotNull(loaded.OfficeAssignment);
            Assert.Equal("Room 101", loaded.OfficeAssignment.Location);
        }
    }

    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsStudents()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.Equal(11, context.Enrollments.Count());
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
