using ContosoUniversity.Models;
using Xunit;
using System;
using System.ComponentModel.DataAnnotations;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        private class ConcretePerson : Person { }

        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var person = new ConcretePerson { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", person.FullName);
        }

        [Fact]
        public void FullName_HandlesNullLastName()
        {
            var person = new ConcretePerson { LastName = null, FirstMidName = "John" };
            Assert.Equal(", John", person.FullName);
        }

        [Fact]
        public void FullName_HandlesNullFirstName()
        {
            var person = new ConcretePerson { LastName = "Smith", FirstMidName = null };
            Assert.Equal("Smith, ", person.FullName);
        }

        [Fact]
        public void LastName_HasRequiredAttribute()
        {
            var attr = typeof(Person).GetProperty("LastName")!
                .GetCustomAttributes(typeof(RequiredAttribute), false);
            Assert.Single(attr);
        }

        [Fact]
        public void LastName_HasStringLengthAttribute_Max50()
        {
            var attr = typeof(Person).GetProperty("LastName")!
                .GetCustomAttributes(typeof(StringLengthAttribute), false)
                .Cast<StringLengthAttribute>().Single();
            Assert.Equal(50, attr.MaximumLength);
        }

        [Fact]
        public void FirstMidName_HasRequiredAttribute()
        {
            var attr = typeof(Person).GetProperty("FirstMidName")!
                .GetCustomAttributes(typeof(RequiredAttribute), false);
            Assert.Single(attr);
        }

        [Fact]
        public void FirstMidName_HasStringLengthAttribute_Max50()
        {
            var attr = typeof(Person).GetProperty("FirstMidName")!
                .GetCustomAttributes(typeof(StringLengthAttribute), false)
                .Cast<StringLengthAttribute>().Single();
            Assert.Equal(50, attr.MaximumLength);
        }
    }

    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            Assert.True(typeof(Person).IsAssignableFrom(typeof(Student)));
        }

        [Fact]
        public void Student_HasEnrollmentDate()
        {
            var student = new Student { EnrollmentDate = new DateTime(2020, 9, 1) };
            Assert.Equal(new DateTime(2020, 9, 1), student.EnrollmentDate);
        }

        [Fact]
        public void Student_HasEnrollmentsCollection()
        {
            var student = new Student { Enrollments = new List<Enrollment>() };
            Assert.NotNull(student.Enrollments);
            Assert.Empty(student.Enrollments);
        }

        [Fact]
        public void Student_FullName_WorksThroughInheritance()
        {
            var student = new Student { FirstMidName = "Alice", LastName = "Wonder" };
            Assert.Equal("Wonder, Alice", student.FullName);
        }

        [Fact]
        public void EnrollmentDate_HasRequiredAttribute()
        {
            var attr = typeof(Student).GetProperty("EnrollmentDate")!
                .GetCustomAttributes(typeof(RequiredAttribute), false);
            Assert.Single(attr);
        }
    }

    public class InstructorTests
    {
        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            Assert.True(typeof(Person).IsAssignableFrom(typeof(Instructor)));
        }

        [Fact]
        public void Instructor_HasHireDate()
        {
            var instructor = new Instructor { HireDate = new DateTime(2000, 1, 1) };
            Assert.Equal(new DateTime(2000, 1, 1), instructor.HireDate);
        }

        [Fact]
        public void Instructor_HasCourseAssignments()
        {
            var instructor = new Instructor
            {
                CourseAssignments = new List<CourseAssignment> { new CourseAssignment() }
            };
            Assert.Single(instructor.CourseAssignments);
        }

        [Fact]
        public void Instructor_HasOfficeAssignment()
        {
            var office = new OfficeAssignment { Location = "Room 101" };
            var instructor = new Instructor { OfficeAssignment = office };
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void HireDate_HasRequiredAttribute()
        {
            var attr = typeof(Instructor).GetProperty("HireDate")!
                .GetCustomAttributes(typeof(RequiredAttribute), false);
            Assert.Single(attr);
        }
    }

    public class CourseTests
    {
        [Fact]
        public void Course_PropertiesSetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
        }

        [Fact]
        public void Course_Title_HasStringLengthAttribute()
        {
            var attr = typeof(Course).GetProperty("Title")!
                .GetCustomAttributes(typeof(StringLengthAttribute), false)
                .Cast<StringLengthAttribute>().Single();
            Assert.Equal(50, attr.MaximumLength);
            Assert.Equal(3, attr.MinimumLength);
        }

        [Fact]
        public void Course_Credits_HasRangeAttribute()
        {
            var attr = typeof(Course).GetProperty("Credits")!
                .GetCustomAttributes(typeof(RangeAttribute), false)
                .Cast<RangeAttribute>().Single();
            Assert.Equal(0, attr.Minimum);
            Assert.Equal(5, attr.Maximum);
        }

        [Fact]
        public void Course_TeachingMaterialImagePath_HasStringLength255()
        {
            var attr = typeof(Course).GetProperty("TeachingMaterialImagePath")!
                .GetCustomAttributes(typeof(StringLengthAttribute), false)
                .Cast<StringLengthAttribute>().Single();
            Assert.Equal(255, attr.MaximumLength);
        }

        [Fact]
        public void Course_HasNavigationProperties()
        {
            var course = new Course
            {
                Department = new Department { Name = "Eng" },
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            Assert.NotNull(course.Department);
            Assert.NotNull(course.Enrollments);
            Assert.NotNull(course.CourseAssignments);
        }
    }

    public class DepartmentTests
    {
        [Fact]
        public void Department_PropertiesSetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };
            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_Name_HasStringLengthAttribute()
        {
            var attr = typeof(Department).GetProperty("Name")!
                .GetCustomAttributes(typeof(StringLengthAttribute), false)
                .Cast<StringLengthAttribute>().Single();
            Assert.Equal(50, attr.MaximumLength);
            Assert.Equal(3, attr.MinimumLength);
        }

        [Fact]
        public void Department_InstructorID_IsNullable()
        {
            var dept = new Department { InstructorID = null };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_HasRowVersion()
        {
            var dept = new Department { RowVersion = new byte[] { 1, 2, 3 } };
            Assert.Equal(3, dept.RowVersion.Length);
        }

        [Fact]
        public void Department_HasAdministratorNavigation()
        {
            var instructor = new Instructor { FirstMidName = "Kim", LastName = "A" };
            var dept = new Department { Administrator = instructor };
            Assert.Equal("Kim", dept.Administrator.FirstMidName);
        }
    }

    public class EnrollmentTests
    {
        [Fact]
        public void Enrollment_PropertiesSetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            };
            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(1, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_IsNullable()
        {
            var enrollment = new Enrollment { Grade = null };
            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_HasCourseNavigation()
        {
            var enrollment = new Enrollment { Course = new Course { Title = "Chem" } };
            Assert.Equal("Chem", enrollment.Course.Title);
        }

        [Fact]
        public void Enrollment_HasStudentNavigation()
        {
            var enrollment = new Enrollment
            {
                Student = new Student { FirstMidName = "A", LastName = "B" }
            };
            Assert.Equal("A", enrollment.Student.FirstMidName);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_AllValuesExist(Grade grade)
        {
            Assert.True(Enum.IsDefined(typeof(Grade), grade));
        }
    }

    public class CourseAssignmentTests
    {
        [Fact]
        public void CourseAssignment_PropertiesSetCorrectly()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };
            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(1050, ca.CourseID);
        }

        [Fact]
        public void CourseAssignment_HasNavigationProperties()
        {
            var ca = new CourseAssignment
            {
                Instructor = new Instructor { FirstMidName = "Kim", LastName = "A" },
                Course = new Course { Title = "Chemistry" }
            };
            Assert.NotNull(ca.Instructor);
            Assert.NotNull(ca.Course);
        }
    }

    public class OfficeAssignmentTests
    {
        [Fact]
        public void OfficeAssignment_PropertiesSetCorrectly()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };
            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Smith 17", oa.Location);
        }

        [Fact]
        public void Location_HasStringLengthAttribute_Max50()
        {
            var attr = typeof(OfficeAssignment).GetProperty("Location")!
                .GetCustomAttributes(typeof(StringLengthAttribute), false)
                .Cast<StringLengthAttribute>().Single();
            Assert.Equal(50, attr.MaximumLength);
        }
    }

    public class NotificationModelTests
    {
        [Fact]
        public void Notification_PropertiesSetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };
            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_IsRead_CanBeTrue()
        {
            var readTime = DateTime.Now;
            var notification = new Notification
            {
                IsRead = true,
                ReadAt = readTime
            };
            Assert.True(notification.IsRead);
            Assert.Equal(readTime, notification.ReadAt);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE)]
        [InlineData(EntityOperation.UPDATE)]
        [InlineData(EntityOperation.DELETE)]
        public void EntityOperation_AllValuesExist(EntityOperation op)
        {
            Assert.True(Enum.IsDefined(typeof(EntityOperation), op));
        }
    }

    public class ErrorViewModelTests
    {
        [Fact]
        public void ShowRequestId_ReturnsTrue_WhenRequestIdIsNotEmpty()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ShowRequestId_ReturnsFalse_WhenRequestIdIsNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ShowRequestId_ReturnsFalse_WhenRequestIdIsEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }
    }
}

