using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_ReturnsAllStudents_WhenNoFilters()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Equal(3, model!.Count);
        }

        [Fact]
        public void Index_FiltersStudents_WhenSearchStringProvided()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Single(model!);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_FiltersStudents_ByFirstName()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Single(model!);
            Assert.Equal("Meredith", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SortsByLastNameAscending_ByDefault()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            var names = model!.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n).ToList(), names);
        }

        [Fact]
        public void Index_SortsByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            var names = model!.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderByDescending(n => n).ToList(), names);
        }

        [Fact]
        public void Index_SortsByDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            var dates = model!.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderBy(d => d).ToList(), dates);
        }

        [Fact]
        public void Index_SortsByDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            var dates = model!.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderByDescending(d => d).ToList(), dates);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_SetsNameSortParm_WhenCurrentSortIsNameDesc()
        {
            _controller.Index("name_desc", null, null, null);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_SetsDateSortParm_WhenCurrentSortIsDate()
        {
            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_ResetsPage_WhenNewSearchString()
        {
            var result = _controller.Index(null, null, "test", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Equal(1, model!.PageIndex);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.Single(model!);
        }

        [Fact]
        public void Index_SetsCurrentFilterInViewBag()
        {
            _controller.Index(null, null, "test", null);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WhenStudentExists()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Details(studentId);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(studentId, model.ID);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewWithStudentWithTodayDate()
        {
            var result = _controller.Create() as ViewResult;
            var model = Assert.IsType<Student>(result!.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenModelIsValid()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var result = _controller.Create(student);
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_AddsStudentToDatabase()
        {
            var initialCount = _context.Students.Count();
            var student = new Student
            {
                FirstMidName = "NewStudent",
                LastName = "LastName",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            _controller.Create(student);
            Assert.Equal(initialCount + 1, _context.Students.Count());
            Assert.Contains(_context.Students, s => s.FirstMidName == "NewStudent");
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenDateIsMinValue()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenDateIsTooOld()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var result = _controller.Create(student);
            Assert.IsType<ViewResult>(result);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null as int?);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            var result = _controller.Edit(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewWithStudent_WhenStudentExists()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Edit(studentId) as ViewResult;
            var model = Assert.IsType<Student>(result!.Model);
            Assert.Equal(studentId, model.ID);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_Post_RedirectsToIndex_WhenModelIsValid()
        {
            var student = _context.Students.AsNoTracking().First();
            student.FirstMidName = "Updated";

            var result = _controller.Edit(student);
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_UpdatesStudent()
        {
            var student = _context.Students.AsNoTracking().First();
            var id = student.ID;
            student.FirstMidName = "UpdatedName";

            _controller.Edit(student);

            var updated = _context.Students.Find(id);
            Assert.Equal("UpdatedName", updated!.FirstMidName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenDateIsInvalid()
        {
            var student = _context.Students.AsNoTracking().First();
            student.EnrollmentDate = DateTime.MinValue;

            var result = _controller.Edit(student);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = _context.Students.AsNoTracking().First();

            var result = _controller.Edit(student);
            Assert.IsType<ViewResult>(result);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            var result = _controller.Delete(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewWithStudent_WhenStudentExists()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Delete(studentId) as ViewResult;
            var model = Assert.IsType<Student>(result!.Model);
            Assert.Equal(studentId, model.ID);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesStudent()
        {
            var student = _context.Students.First();
            var id = student.ID;
            var initialCount = _context.Students.Count();

            _controller.DeleteConfirmed(id);

            Assert.Equal(initialCount - 1, _context.Students.Count());
            Assert.Null(_context.Students.Find(id));
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.DeleteConfirmed(studentId);
            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }
    }
}

