            Assert.IsType<Course>(result.Model);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);
