+
+            var result = _controller.Create(student);
+            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
+            Assert.Equal("Index", redirectResult.ActionName);
+        }
+
+        [Fact]
+        public void Create_Post_AddsStudentToDatabase()
+        {
+            var initialCount = _context.Students.Count();
+            var student = new Student
+            {
+                FirstMidName = "NewStudent",
+                LastName = "LastName",
+                EnrollmentDate = DateTime.Parse("2020-09-01")
+            };
+
+            _controller.Create(student);
+            Assert.Equal(initialCount + 1, _context.Students.Count());
+            Assert.Contains(_context.Students, s => s.FirstMidName == "NewStudent");
+        }
+
+        [Fact]
+        public void Create_Post_ReturnsView_WhenDateIsMinValue()
+        {
+            var student = new Student
+            {
+                FirstMidName = "Test",
+                LastName = "Student",
+                EnrollmentDate = DateTime.MinValue
+            };
+
+            var result = _controller.Create(student);
+            Assert.IsType<ViewResult>(result);
+        }
+
+        [Fact]
+        public void Create_Post_ReturnsView_WhenDateIsTooOld()
+        {
+            var student = new Student
+            {
+                FirstMidName = "Test",
+                LastName = "Student",
+                EnrollmentDate = new DateTime(1752, 12, 31)
+            };
+
+            var result = _controller.Create(student);
+            Assert.IsType<ViewResult>(result);
+        }
+
+        [Fact]
+        public void Create_Post_ReturnsView_WhenModelStateIsInvalid()
+        {
+            _controller.ModelState.AddModelError("LastName", "Required");
+            var student = new Student
+            {
+                FirstMidName = "Test",
+                EnrollmentDate = DateTime.Parse("2020-09-01")
+            };
+
+            var result = _controller.Create(student);
+            Assert.IsType<ViewResult>(result);
+        }
+
+        // --- Edit GET ---
+
+        [Fact]
+        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
+        {
+            var result = _controller.Edit(null as int?);
+            var statusResult = Assert.IsType<StatusCodeResult>(result);
+            Assert.Equal(400, statusResult.StatusCode);
+        }
+
+        [Fact]
+        public void Edit_Get_ReturnsNotFound_WhenStudentDoesNotExist()
+        {
+            var result = _controller.Edit(99999);
+            Assert.IsType<NotFoundResult>(result);
+        }
+
+        [Fact]
+        public void Edit_Get_ReturnsViewWithStudent_WhenStudentExists()
+        {
+            var studentId = _context.Students.First().ID;
+            var result = _controller.Edit(studentId) as ViewResult;
+            var model = Assert.IsType<Student>(result!.Model);
+            Assert.Equal(studentId, model.ID);
+        }
+
+        // --- Edit POST ---
+
+        [Fact]
+        public void Edit_Post_RedirectsToIndex_WhenModelIsValid()
+        {
+            var student = _context.Students.AsNoTracking().First();
+            student.FirstMidName = "Updated";
+
+            var result = _controller.Edit(student);
+            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
+            Assert.Equal("Index", redirectResult.ActionName);
+        }
+
+        [Fact]
+        public void Edit_Post_UpdatesStudent()
+        {
+            var student = _context.Students.AsNoTracking().First();
+            var id = student.ID;
+            student.FirstMidName = "UpdatedName";
+
+            _controller.Edit(student);
+
+            var updated = _context.Students.Find(id);
+            Assert.Equal("UpdatedName", updated!.FirstMidName);
+        }
+
+        [Fact]
+        public void Edit_Post_ReturnsView_WhenDateIsInvalid()
+        {
+            var student = _context.Students.AsNoTracking().First();
+            student.EnrollmentDate = DateTime.MinValue;
+
+            var result = _controller.Edit(student);
+            Assert.IsType<ViewResult>(result);
+        }
+
+        [Fact]
+        public void Edit_Post_ReturnsView_WhenModelStateIsInvalid()
+        {
+            _controller.ModelState.AddModelError("LastName", "Required");
+            var student = _context.Students.AsNoTracking().First();
+
+            var result = _controller.Edit(student);
