using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
                Directory.Delete(_tempDir, true);
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult_WithCourseList()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WhenCourseExists()
        {
            var result = _controller.Details(1050) as ViewResult;
            var model = Assert.IsType<Course>(result!.Model);
            Assert.Equal(1050, model.CourseID);
            Assert.Equal("Chemistry", model.Title);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewWithEmptyCourse()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_AddsCourseToDatabase()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Test Course",
                Credits = 4,
                DepartmentID = 1
            };

            _controller.Create(course, null);
            Assert.NotNull(_context.Courses.Find(8888));
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 7777, Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_RejectsInvalidFileExtension()
        {
            var course = new Course
            {
                CourseID = 5555,
                Title = "Test",
                Credits = 3,
                DepartmentID = 1
            };
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.exe");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _controller.Create(course, fileMock.Object);
            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_RejectsFileTooLarge()
        {
            var course = new Course
            {
                CourseID = 5556,
                Title = "Test",
                Credits = 3,
                DepartmentID = 1
            };
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, fileMock.Object);
            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_AcceptsValidImage()
        {
            var course = new Course
            {
                CourseID = 5557,
                Title = "TestImg",
                Credits = 3,
                DepartmentID = 1
            };
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.png");
            fileMock.Setup(f => f.Length).Returns(1024);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _controller.Create(course, fileMock.Object);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);

            var saved = _context.Courses.Find(5557);
            Assert.NotNull(saved);
            Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null as int?);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenCourseDoesNotExist()
        {
            var result = _controller.Edit(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050) as ViewResult;
            var model = Assert.IsType<Course>(result!.Model);
            Assert.Equal(1050, model.CourseID);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_Post_RedirectsToIndex_WhenValid()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            course.Title = "Updated Chemistry";

            var result = _controller.Edit(course, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_UpdatesCourse()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            course.Title = "Advanced Chemistry";

            _controller.Edit(course, null);

            var updated = _context.Courses.Find(1050);
            Assert.Equal("Advanced Chemistry", updated!.Title);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);

            var result = _controller.Edit(course, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_RejectsInvalidFileExtension()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.pdf");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = _controller.Edit(course, fileMock.Object);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_RejectsOversizedFile()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024);

            var result = _controller.Edit(course, fileMock.Object);
            Assert.IsType<ViewResult>(result);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;
            var model = Assert.IsType<Course>(result!.Model);
            Assert.Equal(1050, model.CourseID);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesCourse()
        {
            var initialCount = _context.Courses.Count();
            _controller.DeleteConfirmed(1050);
            Assert.Equal(initialCount - 1, _context.Courses.Count());
            Assert.Null(_context.Courses.Find(1050));
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1050);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        // --- File extension validation ---

        [Theory]
        [InlineData("test.jpg")]
        [InlineData("test.jpeg")]
        [InlineData("test.png")]
        [InlineData("test.gif")]
        [InlineData("test.bmp")]
        public void Create_Post_AcceptsAllowedExtensions(string fileName)
        {
            var course = new Course
            {
                CourseID = int.Parse("100" + fileName.GetHashCode().ToString().Replace("-", "").Substring(0, 3)),
                Title = "ExtTest",
                Credits = 3,
                DepartmentID = 1
            };
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(1024);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = _controller.Create(course, fileMock.Object);
            Assert.IsType<RedirectToActionResult>(result);
        }
    }
}

