using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult_WithDepartmentList()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as List<Department>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var result = _controller.Details(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewWithDepartment()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var result = _controller.Details(deptId) as ViewResult;
            var model = Assert.IsType<Department>(result!.Model);
            Assert.Equal(deptId, model.DepartmentID);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create();
            Assert.IsType<ViewResult>(result);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var dept = new Department
            {
                Name = "New Dept",
                Budget = 50000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(dept);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_AddsDepartmentToDatabase()
        {
            var initialCount = _context.Departments.Count();
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            _controller.Create(dept);
            Assert.Equal(initialCount + 1, _context.Departments.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                Budget = 50000,
                StartDate = DateTime.Now
            };

            var result = _controller.Create(dept);
            Assert.IsType<ViewResult>(result);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null as int?);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
