using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_ReturnsInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = result!.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_FiltersCoursesForSelectedInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Index(instructor.ID, null) as ViewResult;
            var model = result!.Model as InstructorIndexData;
            Assert.NotNull(model.Courses);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var result = _controller.Details(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewWithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;
            var result = _controller.Details(instructorId) as ViewResult;
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.Equal(instructorId, model.ID);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_AddsInstructorToDatabase()
        {
            var initialCount = _context.Instructors.Count();
            var instructor = new Instructor
            {
                FirstMidName = "Added",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            _controller.Create(instructor, null);
            Assert.Equal(initialCount + 1, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                FirstMidName = "CourseTest",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };
            var courseId = _context.Courses.First().CourseID.ToString();

            _controller.Create(instructor, new[] { courseId });

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.FirstMidName == "CourseTest");
            Assert.Single(saved.CourseAssignments);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateIsInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Now
            };

            var result = _controller.Create(instructor, null);
            Assert.IsType<ViewResult>(result);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null as int?);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                    .ThenInclude(ca => ca.Course)
                .Include(i => i.OfficeAssignment)
                .First();
            var result = _controller.Edit(instructor.ID) as ViewResult;
            Assert.NotNull(result);
            Assert.IsType<Instructor>(result.Model);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenNotExists()
        {
            var result = _controller.Delete(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewWithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;
            var result = _controller.Delete(instructorId) as ViewResult;
            Assert.IsType<Instructor>(result!.Model);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesInstructor()
        {
            // Use an instructor without course assignments to avoid FK issues
            var instructor = new Instructor
            {
                FirstMidName = "ToDelete",
                LastName = "TestInstructor",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var id = instructor.ID;
            var initialCount = _context.Instructors.Count();

            _controller.DeleteConfirmed(id);

            Assert.Equal(initialCount - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "ToDelete2",
                LastName = "TestInstructor",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(instructor.ID);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            var instructor = new Instructor
            {
